/* Example 1: Tightening display headlines */
h1 {
  font-family: 'Montserrat', sans-serif;
  letter-spacing: -0.02em; /* Subtle tightening for display fonts */
  font-weight: 700;
}

/* Example 2: Loosening all caps text slightly */
.call-to-action {
  text-transform: uppercase;
  letter-spacing: 0.05em; /* A bit more space for uppercase text */
  font-size: 0.9em;
}

/* Example 3: Default body text adjustment (often not needed, but can fine-tune) */
p {
  font-family: 'Inter', sans-serif;
  letter-spacing: 0.01em; /* Very subtle adjustment, or leave at normal */
  line-height: 1.5;
}
